<color=#B8DEE5>Officer Abilities are activated when assigned to the bridge of a ship.</color>', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (3304441016, 'officer_ability_name_203', 'Strengthen the Unimatrix', '2025-08-13 17:11:38');
