INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (2449957978, 'officer_flavor_text_134', '<color=#40CFFF>CLASS:</color> COMMAND
<color=#40CFFF>GROUP:</color> TERRAN EMPIRE
<color=#40CFFF>FACTION:</color> NONE

Her Imperial Majesty, Mother of the Fatherland, Overlord of Vulcan – Emperor Philippa Georgiou carries many titles. They tell the story of her all-encompassing rule over the Terran Empire. Taking what she wants and crushing any who dare oppose her, the Emperor sees herself as untouchable, despite the many enemies she has made along the way.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (2449957978, 'officer_name_134', 'Emperor Georgiou', '2025-08-13 17:11:38');
