INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1958876935, 'officer_flavor_text_135', '<color=#40CFFF>CLASS:</color> ENGINEERING
<color=#40CFFF>GROUP:</color> TERRAN EMPIRE
<color=#40CFFF>FACTION:</color> NONE

Unlike her USS Discovery counterpart, Captain Tilly is charismatic, ruthless, and bloodthirsty. Leaving a trail of destruction in her wake in any system she targets, her reputation has garnered her several nicknames, including “The Slayer of Sorna Prime”, “The Witch of Wurna Minor", and “Captain Killy” – each of which she relishes.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (1958876935, 'officer_name_135', 'Captain Tilly', '2025-08-13 17:11:38');
